import { GoogleGenAI } from "@google/genai";
import { WeatherData } from "../types";

// Initialize Gemini
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getVenueWeather = async (): Promise<WeatherData> => {
  try {
    const modelId = 'gemini-2.5-flash'; 

    // We use Gemini with Grounding (Google Search) to get real-time info
    const response = await ai.models.generateContent({
      model: modelId,
      contents: "Find the current weather forecast for right now in El Poblet de las Atalayas, Alicante, Spain. Also, give a very brief 1-sentence poetic description of the weather suitable for a wedding website.",
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        // We ask for a specific schema to make parsing easy
        responseSchema: {
          type: "OBJECT",
          properties: {
            temperature: { type: "STRING", description: "Current temperature e.g. 24°C" },
            condition: { type: "STRING", description: "Short condition e.g. Sunny, Cloudy" },
            description: { type: "STRING", description: "Poetic description of the current atmosphere" },
            location: { type: "STRING", description: "The confirmed location name" }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);

    // Map condition to emoji
    let icon = "☀️";
    const cond = data.condition.toLowerCase();
    if (cond.includes("cloud")) icon = "⛅";
    if (cond.includes("rain")) icon = "🌧️";
    if (cond.includes("clear")) icon = "☀️";
    if (cond.includes("night")) icon = "🌙";

    return {
      temperature: data.temperature,
      condition: data.condition,
      description: data.description,
      location: data.location,
      icon
    };

  } catch (error) {
    console.error("Error fetching weather:", error);
    // Fallback if API fails
    return {
      temperature: "22°C",
      condition: "Soleado",
      description: "Un día radiante y perfecto en la costa alicantina.",
      icon: "☀️",
      location: "Alicante, España"
    };
  }
};

export const generateThankYouMessage = async (name: string): Promise<string> => {
  try {
     const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Generate a short, elegant, and warm thank you message (in Spanish) for a guest named ${name} who just RSVP'd to Rafa and Laura's wedding. Keep it under 20 words.`,
    });
    return response.text || "¡Gracias por confirmar tu asistencia!";
  } catch (e) {
    return "¡Gracias por confirmar tu asistencia!";
  }
}

