import { GoogleGenAI } from "@google/genai";
import { WeatherData } from "../types";

// Initialize Gemini
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getVenueWeather = async (): Promise<WeatherData> => {
  try {
    const modelId = 'gemini-2.5-flash'; 

    // We use Gemini with Grounding (Google Search) to get real-time info.
    // NOTE: responseMimeType: 'application/json' is not compatible with tools in some configurations,
    // so we ask for JSON in the prompt text and parse it manually.
    const response = await ai.models.generateContent({
      model: modelId,
      contents: `Find the current weather forecast for right now in El Poblet de las Atalayas, Alicante, Spain. 
      Return a valid JSON object with the following keys:
      - temperature: string (e.g. "24°C")
      - condition: string (short description in Spanish, e.g. "Soleado")
      - description: string (1 short poetic sentence in Spanish about the weather, suitable for a wedding website)
      - location: string (the confirmed location name)

      Ensure the response is ONLY valid JSON, no markdown formatting.`,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    let text = response.text;
    if (!text) throw new Error("No response from AI");

    // Clean up potential markdown code blocks if the model includes them
    text = text.replace(/```json\n?|```/g, '').trim();

    const data = JSON.parse(text);

    // Map condition to emoji
    let icon = "☀️";
    const cond = (data.condition || "").toLowerCase();
    if (cond.includes("nub") || cond.includes("cloud") || cond.includes("cubierto")) icon = "⛅";
    if (cond.includes("lluvia") || cond.includes("rain") || cond.includes("llov")) icon = "🌧️";
    if (cond.includes("despejado") || cond.includes("sol") || cond.includes("clear")) icon = "☀️";
    if (cond.includes("noche") || cond.includes("night") || cond.includes("luna")) icon = "🌙";
    if (cond.includes("viento") || cond.includes("wind")) icon = "💨";

    return {
      temperature: data.temperature || "24°C",
      condition: data.condition || "Soleado",
      description: data.description || "Un día radiante y perfecto en la costa alicantina.",
      location: data.location || "Alicante, España",
      icon
    };

  } catch (error) {
    console.error("Error fetching weather:", error);
    // Fallback if API fails
    return {
      temperature: "22°C",
      condition: "Soleado",
      description: "Un día radiante y perfecto en la costa alicantina.",
      icon: "☀️",
      location: "Alicante, España"
    };
  }
};

