import React, { useState } from 'react';
import { User, Check, X } from 'lucide-react';

interface Seat {
  id: string;
  guestName: string | null; // If null, it's empty
  isReserved: boolean;
}

interface TableData {
  id: string;
  label: string;
  type: 'round' | 'rect';
  x: number; // Percent 0-100
  y: number; // Percent 0-100
  seats: Seat[];
}

// Helper to generate mock seats
const generateSeats = (count: number, prefix: string): Seat[] => {
  const commonNames = ["Carlos", "Ana", "Luis", "Maria", "Pedro", "Sofia", "Jorge", "Lucia", "Miguel", "Elena"];
  return Array.from({ length: count }).map((_, i) => {
    // 70% chance of being occupied for demo purposes
    const isOccupied = Math.random() > 0.3;
    return {
      id: `${prefix}-${i}`,
      guestName: isOccupied ? `${commonNames[Math.floor(Math.random() * commonNames.length)]} ${String.fromCharCode(65 + i)}.` : null,
      isReserved: isOccupied
    };
  });
};

export const SeatingChart: React.FC = () => {
  // Define tables layout
  const tables: TableData[] = [
    // Head Table (Presidencial)
    {
      id: 'head-table',
      label: 'Presidencial',
      type: 'rect',
      x: 50,
      y: 10,
      seats: [
        { id: 'h-1', guestName: 'Rafa', isReserved: true },
        { id: 'h-2', guestName: 'Laura', isReserved: true }
      ]
    },
    // Generate 11 Round tables for ~110 guests
    ...Array.from({ length: 11 }).map((_, i) => ({
      id: `table-${i + 1}`,
      label: `Mesa ${i + 1}`,
      type: 'round' as const,
      // Simple grid logic for positioning: 3 columns
      x: 20 + (i % 3) * 30, 
      y: 30 + Math.floor(i / 3) * 20,
      seats: generateSeats(10, `t${i + 1}`)
    }))
  ];

  const [selectedSeat, setSelectedSeat] = useState<{ tableId: string, seatId: string } | null>(null);
  const [requestName, setRequestName] = useState("");
  const [showModal, setShowModal] = useState(false);
  const [localTables, setLocalTables] = useState(tables);

  const handleSeatClick = (tableId: string, seat: Seat) => {
    if (!seat.isReserved) {
      setSelectedSeat({ tableId, seatId: seat.id });
      setShowModal(true);
      setRequestName("");
    }
  };

  const handleRequestSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSeat || !requestName) return;

    // Update local state to show the reservation
    setLocalTables(prev => prev.map(t => {
      if (t.id === selectedSeat.tableId) {
        return {
          ...t,
          seats: t.seats.map(s => s.id === selectedSeat.seatId ? { ...s, guestName: requestName, isReserved: true } : s)
        };
      }
      return t;
    }));

    setShowModal(false);
    setSelectedSeat(null);
    alert(`¡Solicitud enviada! Te gustaría sentarte en la ${localTables.find(t => t.id === selectedSeat.tableId)?.label}.`);
  };

  return (
    <div className="relative w-full h-[800px] bg-stone-50 rounded-xl shadow-inner border border-stone-200 overflow-hidden select-none">

      {/* Floor Pattern */}
      <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(#d4af37 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

      <div className="absolute top-4 left-4 z-10 bg-white/80 backdrop-blur p-3 rounded-lg shadow border border-gray-100 text-xs font-sans">
        <div className="flex items-center gap-2 mb-1">
          <div className="w-3 h-3 rounded-full bg-sakura-pink border border-pink-300"></div>
          <span>Ocupado</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-white border border-dashed border-gray-400"></div>
          <span>Disponible (Click para pedir)</span>
        </div>
      </div>

      {localTables.map((table) => (
        <div
          key={table.id}
          className="absolute transform -translate-x-1/2 -translate-y-1/2 transition-all duration-500 hover:scale-105"
          style={{ left: `${table.x}%`, top: `${table.y}%` }}
        >
          {/* Table Surface */}
          <div 
            className={`
              relative flex items-center justify-center shadow-lg border-2 border-wedding-gold/40 bg-white
              ${table.type === 'rect' ? 'w-48 h-20 rounded-lg' : 'w-32 h-32 rounded-full'}
            `}
          >
            <span className="font-cinzel text-gray-800 font-bold text-xs md:text-sm text-center px-1">
              {table.label}
            </span>

            {/* Render Seats */}
            {table.seats.map((seat, idx) => {
              // Position logic
              let style: React.CSSProperties = {};

              if (table.type === 'round') {
                const angle = (idx * (360 / table.seats.length)) * (Math.PI / 180);
                const radius = 60; // Distance from center
                style = {
                  left: `calc(50% + ${Math.cos(angle) * radius}px)`,
                  top: `calc(50% + ${Math.sin(angle) * radius}px)`,
                };
              } else {
                // Rectangular (Head table) - Side by side
                style = {
                  top: '50%',
                  left: idx === 0 ? '-20px' : 'calc(100% + 20px)',
                  transform: 'translate(-50%, -50%)' // Center the chair itself
                };
              }

              return (
                <div
                  key={seat.id}
                  onClick={() => handleSeatClick(table.id, seat)}
                  className={`
                    absolute w-8 h-8 rounded-full flex items-center justify-center cursor-pointer group/seat
                    transition-all duration-300 shadow-sm
                    ${table.type === 'round' ? '-translate-x-1/2 -translate-y-1/2' : ''}
                    ${seat.isReserved 
                      ? 'bg-sakura-pink border border-pink-300' 
                      : 'bg-white border-2 border-dashed border-gray-300 hover:border-wedding-gold hover:bg-yellow-50'}
                  `}
                  style={style}
                >
                  {seat.isReserved ? (
                    <User className="w-4 h-4 text-pink-700 opacity-50" />
                  ) : (
                    <span className="text-gray-300 text-[10px]">+</span>
                  )}

                  {/* Tooltip */}
                  <div className="absolute bottom-full mb-2 hidden group-hover/seat:block z-50 whitespace-nowrap">
                    <div className="bg-gray-800 text-white text-xs py-1 px-2 rounded shadow-lg relative">
                      {seat.guestName || "¡Siéntate aquí!"}
                      <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-800"></div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      ))}

      {/* Request Seat Modal */}
      {showModal && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-sm p-4">
          <div className="bg-white p-6 rounded-xl shadow-2xl max-w-sm w-full animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-cinzel text-lg font-bold text-gray-800">Sugerir Sitio</h3>
