import React, { useState, useRef, useEffect } from 'react';
import { Music, Play } from 'lucide-react';

export const MusicPlayer: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);

  // Using multiple sources for better compatibility
  // Source: Wikimedia Commons (Public Domain) - Canon in D
  const MP3_URL = "https://upload.wikimedia.org/wikipedia/commons/transcoded/2/21/Pachelbel%27s_Canon_in_D_-_Violin_%26_Cello_-_Brengle_%26_Schuett.ogg/Pachelbel%27s_Canon_in_D_-_Violin_%26_Cello_-_Brengle_%26_Schuett.ogg.mp3";
  const OGG_URL = "https://upload.wikimedia.org/wikipedia/commons/2/21/Pachelbel%27s_Canon_in_D_-_Violin_%26_Cello_-_Brengle_%26_Schuett.ogg";

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = 0.3; // Start with low volume (30%)

      // Attempt to autoplay
      const playPromise = audioRef.current.play();

      if (playPromise !== undefined) {
        playPromise
          .then(() => {
            setIsPlaying(true);
          })
          .catch(() => {
            // Auto-play was prevented by browser policy (user interaction needed)
            // Silently fail to avoid console spam, waiting for user interaction
            setIsPlaying(false);
          });
      }
    }
  }, []);

  const togglePlay = () => {
    if (!audioRef.current) return;

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      const playPromise = audioRef.current.play();
      if (playPromise !== undefined) {
        playPromise
          .then(() => setIsPlaying(true))
          .catch((e) => {
             console.log("Playback failed (interaction required or error):", e.message);
             setIsPlaying(false);
          });
      }
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-center gap-2">
      <audio 
        ref={audioRef} 
        loop 
        preload="auto"
        onError={() => {
          console.log("Audio source load error");
          setIsPlaying(false);
        }}
      >
        <source src={MP3_URL} type="audio/mpeg" />
        <source src={OGG_URL} type="audio/ogg" />
      </audio>

      {/* Floating Music Button */}
      <button
        onClick={togglePlay}
        className={`
          relative w-12 h-12 rounded-full flex items-center justify-center shadow-lg transition-all duration-500
          ${isPlaying 
            ? 'bg-wedding-gold text-white shadow-wedding-gold/40' 
            : 'bg-white text-gray-400 hover:text-wedding-gold border border-gray-200'}
        `}
        title={isPlaying ? "Pausar Música" : "Reproducir Música"}
      >
        {/* Animated Ring when playing */}
        {isPlaying && (
           <span className="absolute inline-flex h-full w-full rounded-full bg-wedding-gold opacity-75 animate-ping"></span>
        )}

        {/* Icon */}
        <div className="relative z-10">
          {isPlaying ? (
            <Music className="w-5 h-5 animate-[sway_3s_ease-in-out_infinite]" />
          ) : (
            <Play className="w-5 h-5 ml-1" />
          )}
        </div>
      </button>

      {/* Label */}
      <span className={`text-[10px] font-cinzel tracking-wider font-bold bg-white/80 backdrop-blur px-2 py-0.5 rounded shadow-sm transition-opacity duration-300 ${isPlaying ? 'opacity-0 hover:opacity-100' : 'text-gray-500'}`}>
        {isPlaying ? 'Sonando' : 'Música'}
      </span>
    </div>
  );
};

