import React, { useState } from 'react';
import { User, X, AlertCircle } from 'lucide-react';
import { TableData, Seat } from '../types';

interface SeatingChartProps {
  tables: TableData[];
  onSuggestSeat: (tableId: string, seatId: string, name: string) => void;
}

export const SeatingChart: React.FC<SeatingChartProps> = ({ tables, onSuggestSeat }) => {
  const [selectedSeat, setSelectedSeat] = useState<{ tableId: string, seatId: string } | null>(null);
  const [requestName, setRequestName] = useState("");
  const [showModal, setShowModal] = useState(false);

  const handleSeatClick = (tableId: string, seat: Seat) => {
    // Guests can only click empty seats or seats they haven't already suggested/reserved
    if (!seat.isReserved && !seat.suggestedBy) {
      setSelectedSeat({ tableId, seatId: seat.id });
      setShowModal(true);
      setRequestName("");
    }
  };

  const handleRequestSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSeat || !requestName) return;

    onSuggestSeat(selectedSeat.tableId, selectedSeat.seatId, requestName);

    setShowModal(false);
    setSelectedSeat(null);
  };

  return (
    <div className="relative w-full h-[600px] lg:h-[800px] bg-stone-50 rounded-xl shadow-inner border border-stone-200 overflow-hidden select-none touch-pan-y">

      {/* Floor Pattern */}
      <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(#d4af37 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

      {/* Legend */}
      <div className="absolute top-4 left-4 z-10 bg-white/90 backdrop-blur p-3 rounded-lg shadow border border-gray-100 text-xs font-sans">
        <div className="flex items-center gap-2 mb-1">
          <div className="w-3 h-3 rounded-full bg-pink-400 border border-pink-500"></div>
          <span>Ocupado</span>
        </div>
        <div className="flex items-center gap-2 mb-1">
          <div className="w-3 h-3 rounded-full bg-orange-300 border border-orange-400 animate-pulse"></div>
          <span>Sugerencia Pendiente</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-white border border-dashed border-gray-400"></div>
          <span>Disponible (Click para pedir)</span>
        </div>
      </div>

      {tables.map((table) => (
        <div
          key={table.id}
          className="absolute transform -translate-x-1/2 -translate-y-1/2 transition-all duration-500"
          style={{ left: `${table.x}%`, top: `${table.y}%` }}
        >
          {/* Table Surface */}
          <div 
            className={`
              relative flex items-center justify-center shadow-lg border-2 border-wedding-gold/40 bg-white
              ${table.type === 'rect' ? 'w-48 h-20 rounded-lg' : 'w-24 h-24 md:w-32 md:h-32 rounded-full'}
            `}
          >
            <span className="font-cinzel text-gray-800 font-bold text-[10px] md:text-sm text-center px-1 leading-tight">
              {table.label}
            </span>

            {/* Render Seats */}
            {table.seats.map((seat, idx) => {
              // Position logic
              let style: React.CSSProperties = {};

              if (table.type === 'round') {
                const angle = (idx * (360 / table.seats.length)) * (Math.PI / 180);
                const radius = 50; // Distance from center
                // Responsive radius adjustment could be done here with media queries or JS window width
                const responsiveRadius = window.innerWidth < 768 ? 40 : 60; 

                style = {
                  left: `calc(50% + ${Math.cos(angle) * responsiveRadius}px)`,
                  top: `calc(50% + ${Math.sin(angle) * responsiveRadius}px)`,
                };
              } else {
                // Rectangular (Head table)
                style = {
                  top: '50%',
                  left: idx === 0 ? '-20px' : 'calc(100% + 20px)',
                  transform: 'translate(-50%, -50%)' 
                };
              }

              const isPending = !!seat.suggestedBy;

              return (
                <div
                  key={seat.id}
                  onClick={() => handleSeatClick(table.id, seat)}
                  className={`
                    absolute w-6 h-6 md:w-8 md:h-8 rounded-full flex items-center justify-center cursor-pointer group/seat
                    transition-all duration-300 shadow-sm z-20
                    ${table.type === 'round' ? '-translate-x-1/2 -translate-y-1/2' : ''}
                    ${seat.isReserved 
                      ? 'bg-sakura-pink border border-pink-400' 
                      : isPending 
                        ? 'bg-orange-100 border border-orange-300' 
                        : 'bg-white border-2 border-dashed border-gray-300 hover:border-wedding-gold hover:bg-yellow-50'}
                  `}
                  style={style}
                >
                  {seat.isReserved ? (
                    <User className="w-3 h-3 md:w-4 md:h-4 text-pink-700 opacity-60" />
                  ) : isPending ? (
                    <AlertCircle className="w-3 h-3 md:w-4 md:h-4 text-orange-500" />
                  ) : (
                    <span className="text-gray-300 text-[10px]">+</span>
                  )}

                  {/* Tooltip */}
                  <div className="absolute bottom-full mb-2 hidden group-hover/seat:block z-50 whitespace-nowrap pointer-events-none">
                    <div className="bg-gray-800 text-white text-xs py-1 px-2 rounded shadow-lg relative">
                      {seat.isReserved ? seat.guestName : isPending ? "Solicitado..." : "¡Pídelo!"}
                      <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-800"></div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      ))}

      {/* Request Seat Modal */}
      {showModal && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-sm p-4">
          <div className="bg-white p-6 rounded-xl shadow-2xl max-w-sm w-full animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-cinzel text-lg font-bold text-gray-800">Sugerir Sitio</h3>
              <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-gray-600">
                <X className="w-5 h-5" />
              </button>
            </div>

            <p className="text-sm text-gray-600 mb-4">
              ¿Te gustaría sentarte aquí? Envíanos tu nombre y lo revisaremos.
              <br/>
              <span className="text-xs text-orange-500 font-bold">* No se confirmará automáticamente.</span>
            </p>

            <form onSubmit={handleRequestSubmit}>
              <input 
                type="text" 
                placeholder="Tu Nombre" 
                autoFocus
                required
                className="w-full border border-gray-300 rounded p-2 mb-4 focus:border-wedding-gold focus:outline-none"
                value={requestName}
                onChange={(e) => setRequestName(e.target.value)}
              />
              <button 
                type="submit" 
                className="w-full bg-gray-900 text-white py-2 rounded hover:bg-wedding-gold transition-colors font-cinzel text-sm"
              >
                Enviar Sugerencia
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { TableData, Seat } from '../types';
import { Move, Check, X, User, Trash2, Edit2 } from 'lucide-react';

interface SeatingPlannerProps {
  tables: TableData[];
  onUpdateTables: (tables: TableData[]) => void;
}

export const SeatingPlanner: React.FC<SeatingPlannerProps> = ({ tables, onUpdateTables }) => {
  const [draggingTable, setDraggingTable] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Seat Management Modal State
  const [selectedSeat, setSelectedSeat] = useState<{ tableId: string, seat: Seat } | null>(null);
  const [guestNameInput, setGuestNameInput] = useState("");

  // Table Rename State
  const [editingTableId, setEditingTableId] = useState<string | null>(null);
  const [tableNameInput, setTableNameInput] = useState("");

  // --- Drag & Drop Logic ---
  const handleMouseDown = (e: React.MouseEvent, tableId: string) => {
    // Only drag if clicking the table body, not a seat
    if ((e.target as HTMLElement).closest('.seat-node')) return;
    setDraggingTable(tableId);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!draggingTable || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    // Clamp values 0-100
    const clampedX = Math.max(0, Math.min(100, x));
    const clampedY = Math.max(0, Math.min(100, y));

    const updatedTables = tables.map(t => 
      t.id === draggingTable ? { ...t, x: clampedX, y: clampedY } : t
    );
    onUpdateTables(updatedTables);
  };

  const handleMouseUp = () => {
    setDraggingTable(null);
  };

  // --- Seat Logic ---
  const handleSeatClick = (tableId: string, seat: Seat) => {
    setSelectedSeat({ tableId, seat });
    setGuestNameInput(seat.guestName || (seat.suggestedBy || ""));
  };

  const saveSeat = () => {
    if (!selectedSeat) return;

    const updatedTables = tables.map(t => {
      if (t.id === selectedSeat.tableId) {
        return {
          ...t,
          seats: t.seats.map(s => {
            if (s.id === selectedSeat.seat.id) {
              return {
                ...s,
                guestName: guestNameInput,
                isReserved: !!guestNameInput,
                suggestedBy: null // Clear suggestion if manually saved
              };
            }
            return s;
          })
        };
      }
      return t;
    });
    onUpdateTables(updatedTables);
    setSelectedSeat(null);
  };

  const clearSeat = () => {
    setGuestNameInput("");
    // We'll treat the save with empty string as clear
    if (!selectedSeat) return;
    const updatedTables = tables.map(t => {
      if (t.id === selectedSeat.tableId) {
        return {
          ...t,
          seats: t.seats.map(s => {
            if (s.id === selectedSeat.seat.id) {
              return { ...s, guestName: null, isReserved: false, suggestedBy: null };
            }
            return s;
          })
        };
      }
      return t;
    });
    onUpdateTables(updatedTables);
    setSelectedSeat(null);
  };

  const approveSuggestion = () => {
    if (!selectedSeat?.seat.suggestedBy) return;
    setGuestNameInput(selectedSeat.seat.suggestedBy);
    // After setting input, call save effectively
    const updatedTables = tables.map(t => {
      if (t.id === selectedSeat.tableId) {
        return {
          ...t,
          seats: t.seats.map(s => {
            if (s.id === selectedSeat.seat.id) {
              return {
                ...s,
                guestName: s.suggestedBy,
                isReserved: true,
                suggestedBy: null
              };
            }
            return s;
          })
        };
      }
      return t;
    });
    onUpdateTables(updatedTables);
    setSelectedSeat(null);
  };

  // --- Table Rename Logic ---
  const startRenaming = (table: TableData) => {
    setEditingTableId(table.id);
    setTableNameInput(table.label);
  };

  const saveTableName = () => {
    if (editingTableId) {
      const updatedTables = tables.map(t => 
        t.id === editingTableId ? { ...t, label: tableNameInput } : t
      );
      onUpdateTables(updatedTables);
      setEditingTableId(null);
    }
  };

  return (
    <div className="flex flex-col h-full">
      <div className="bg-yellow-50 p-4 border-b border-yellow-200 text-sm text-yellow-800 flex justify-between items-center">
        <p>🎮 <strong>Modo Editor:</strong> Arrastra las mesas para moverlas. Haz clic en las sillas para asignar invitados o aprobar sugerencias.</p>
      </div>

      <div 
        className="relative flex-grow bg-slate-100 overflow-hidden cursor-crosshair"
        ref={containerRef}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        style={{ minHeight: '600px', backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)', backgroundSize: '30px 30px' }}
      >
        {tables.map((table) => (
          <div
            key={table.id}
            className={`absolute transform -translate-x-1/2 -translate-y-1/2 select-none group ${draggingTable === table.id ? 'z-50 cursor-grabbing' : 'z-10 cursor-grab'}`}
            style={{ left: `${table.x}%`, top: `${table.y}%` }}
            onMouseDown={(e) => handleMouseDown(e, table.id)}
          >
            {/* Table Body */}
            <div 
              className={`
                relative flex items-center justify-center shadow-xl border-4
                transition-colors duration-200
                ${draggingTable === table.id ? 'border-blue-400 bg-blue-50' : 'border-wedding-gold bg-white'}
                ${table.type === 'rect' ? 'w-48 h-24 rounded-lg' : 'w-32 h-32 rounded-full'}
              `}
            >
              {editingTableId === table.id ? (
                <div className="absolute z-50">
                   <input 
                      autoFocus
                      className="w-24 text-center border-b border-blue-500 focus:outline-none bg-transparent"
                      value={tableNameInput}
                      onChange={(e) => setTableNameInput(e.target.value)}
                      onBlur={saveTableName}
                      onKeyDown={(e) => e.key === 'Enter' && saveTableName()}
                   />
                </div>
              ) : (
                <div 
                  className="flex items-center gap-1 cursor-text hover:bg-gray-100 px-2 py-1 rounded"
                  onDoubleClick={() => startRenaming(table)}
                >
                  <span className="font-bold text-sm text-gray-800">{table.label}</span>
                  <Edit2 className="w-3 h-3 text-gray-400 opacity-0 group-hover:opacity-100" />
                </div>
              )}

              {/* Seats */}
              {table.seats.map((seat, idx) => {
                 let style: React.CSSProperties = {};
                 if (table.type === 'round') {
                   const angle = (idx * (360 / table.seats.length)) * (Math.PI / 180);
                   const radius = 65; 
                   style = { left: `calc(50% + ${Math.cos(angle) * radius}px)`, top: `calc(50% + ${Math.sin(angle) * radius}px)` };
                 } else {
                   style = { top: '50%', left: idx === 0 ? '-25px' : 'calc(100% + 25px)', transform: 'translate(-50%, -50%)' };
                 }

                 const hasSuggestion = !!seat.suggestedBy;

                 return (
                   <div
                     key={seat.id}
                     className={`seat-node absolute w-9 h-9 rounded-full flex items-center justify-center cursor-pointer shadow-sm hover:scale-110 transition-transform border-2
                       ${table.type === 'round' ? '-translate-x-1/2 -translate-y-1/2' : ''}
                       ${seat.isReserved ? 'bg-green-100 border-green-500 text-green-700' : hasSuggestion ? 'bg-orange-100 border-orange-500 text-orange-700 animate-pulse' : 'bg-white border-gray-300 text-gray-400'}
                     `}
                     style={style}
                     onMouseDown={(e) => e.stopPropagation()} // Prevent dragging table
                     onClick={() => handleSeatClick(table.id, seat)}
                     title={seat.guestName || (hasSuggestion ? `Sugerido: ${seat.suggestedBy}` : "Vacío")}
                   >
                     {hasSuggestion ? '?' : <User className="w-4 h-4" />}
                   </div>
                 );
              })}
            </div>
          </div>
        ))}
      </div>

      {/* Seat Editor Modal */}
      {selectedSeat && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/40 backdrop-blur-sm">
          <div className="bg-white p-6 rounded-xl shadow-2xl w-full max-w-sm">
            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
              <User className="w-5 h-5 text-wedding-gold" />
              Editar Asiento
            </h3>

            {selectedSeat.seat.suggestedBy && !selectedSeat.seat.isReserved && (
              <div className="mb-4 bg-orange-50 border border-orange-200 p-3 rounded-lg">
                <p className="text-xs text-orange-600 font-bold uppercase mb-1">Sugerencia Recibida</p>
                <p className="text-gray-800">"{selectedSeat.seat.suggestedBy}" quiere este sitio.</p>
                <div className="flex gap-2 mt-2">
                  <button 
                    onClick={approveSuggestion}
                    className="flex-1 bg-green-500 text-white py-1 rounded text-sm hover:bg-green-600 flex items-center justify-center gap-1"
                  >
                    <Check className="w-3 h-3" /> Aprobar
                  </button>
                  <button 
                    onClick={clearSeat}
                    className="flex-1 bg-red-500 text-white py-1 rounded text-sm hover:bg-red-600 flex items-center justify-center gap-1"
                  >
                    <X className="w-3 h-3" /> Rechazar
                  </button>
                </div>
              </div>
            )}

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nombre del Invitado</label>
                <input 
                  type="text" 
                  value={guestNameInput}
                  onChange={(e) => setGuestNameInput(e.target.value)}
                  className="w-full border rounded p-2 focus:ring-2 focus:ring-wedding-gold outline-none"
                  placeholder="Vacío"
                />
              </div>

              <div className="flex justify-between pt-4 border-t">
                <button 
                  onClick={clearSeat}
                  className="text-red-500 hover:bg-red-50 px-3 py-2 rounded flex items-center gap-1 text-sm"
                >
                  <Trash2 className="w-4 h-4" /> Liberar
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setSelectedSeat(null)}
                    className="px-4 py-2 text-gray-500 hover:text-gray-700 text-sm"
                  >
                    Cancelar
                  </button>
                  <button 
                    onClick={saveSeat}
                    className="bg-gray-900 text-white px-4 py-2 rounded hover:bg-gray-800 text-sm"
                  >
                    Guardar
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

