import React, { useState, useRef, useMemo } from 'react';
import { TableData, Seat, Guest, GuestCategory } from '../types';
import { Check, X, User, Trash2, Edit2, Plus, Save, Circle, Square, MousePointer2, GripVertical, Search } from 'lucide-react';

interface SeatingPlannerProps {
  tables: TableData[];
  onUpdateTables: (tables: TableData[]) => void;
  guests?: Guest[]; // Optional prop for drag and drop list
}

export const SeatingPlanner: React.FC<SeatingPlannerProps> = ({ tables, onUpdateTables, guests = [] }) => {
  const [draggingTable, setDraggingTable] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Seat Management Modal State
  const [selectedSeat, setSelectedSeat] = useState<{ tableId: string, seat: Seat } | null>(null);
  const [guestNameInput, setGuestNameInput] = useState("");
  const [guestCategoryInput, setGuestCategoryInput] = useState<GuestCategory>('other');

  // Table Rename State
  const [editingTableId, setEditingTableId] = useState<string | null>(null);
  const [tableNameInput, setTableNameInput] = useState("");

  // Guest List Search
  const [searchTerm, setSearchTerm] = useState("");

  // --- Computed Data ---

  // Flatten all seated guests to find who is where
  const seatedGuestsMap = useMemo(() => {
    const map = new Map<string, string>(); // Name -> TableLabel
    tables.forEach(t => {
      t.seats.forEach(s => {
        if (s.guestName) map.set(s.guestName.toLowerCase().trim(), t.label);
      });
    });
    return map;
  }, [tables]);

  // --- Actions ---

  const handleSaveAll = () => {
    onUpdateTables([...tables]); 
    alert("¡Distribución de mesas guardada correctamente!");
  };

  const handleAddTable = (type: 'round' | 'rect') => {
    const newId = `mesa-${Date.now()}`;
    const newTable: TableData = {
      id: newId,
      label: `Nueva Mesa`,
      type: type,
      x: 50, // Center
      y: 50, // Center
      seats: Array.from({ length: type === 'round' ? 10 : 6 }).map((_, i) => ({
        id: `${newId}-${i}`,
        guestName: null,
        isReserved: false,
        suggestedBy: null,
        category: 'other'
      }))
    };
    onUpdateTables([...tables, newTable]);
  };

  const handleDeleteTable = (tableId: string) => {
    if (window.confirm("¿Seguro que quieres eliminar esta mesa y todos sus invitados?")) {
      const filtered = tables.filter(t => t.id !== tableId);
      onUpdateTables(filtered);
      setEditingTableId(null);
    }
  };

  // --- Drag & Drop Tables ---
  const handleMouseDown = (e: React.MouseEvent, tableId: string) => {
    // Only drag if clicking the table body, not a seat, input, or delete button
    if ((e.target as HTMLElement).closest('.seat-node')) return;
    if ((e.target as HTMLElement).closest('.delete-btn')) return; // Explicitly ignore delete button
    if ((e.target as HTMLElement).tagName === 'INPUT') return;
    if ((e.target as HTMLElement).tagName === 'BUTTON') return;

    setDraggingTable(tableId);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!draggingTable || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const clampedX = Math.max(0, Math.min(100, x));
    const clampedY = Math.max(0, Math.min(100, y));

    const updatedTables = tables.map(t => 
      t.id === draggingTable ? { ...t, x: clampedX, y: clampedY } : t
    );
    onUpdateTables(updatedTables);
  };

  const handleMouseUp = () => {
    setDraggingTable(null);
  };

  // --- Guest List Drag & Drop ---
  const handleDragStartGuest = (e: React.DragEvent, name: string) => {
    e.dataTransfer.setData("guestName", name);
    e.dataTransfer.effectAllowed = "copy";
  };

  const handleDragOverSeat = (e: React.DragEvent) => {
    e.preventDefault(); // Necessary to allow dropping
    e.dataTransfer.dropEffect = "copy";
  };

  const handleDropOnSeat = (e: React.DragEvent, tableId: string, seat: Seat) => {
    e.preventDefault();
    const name = e.dataTransfer.getData("guestName");
    if (name) {
      // Assign guest to seat
      const updatedTables = tables.map(t => {
        if (t.id === tableId) {
          return {
            ...t,
            seats: t.seats.map(s => {
              if (s.id === seat.id) {
                return {
                  ...s,
                  guestName: name,
                  isReserved: true,
                  suggestedBy: null,
                  category: 'friend' as GuestCategory // Default to friend when dragging, can edit later
                };
              }
              return s;
            })
          };
        }
        return t;
      });
      onUpdateTables(updatedTables);
    }
  };

  // --- Seat Logic ---
  const handleSeatClick = (tableId: string, seat: Seat) => {
    setSelectedSeat({ tableId, seat });
    setGuestNameInput(seat.guestName || (seat.suggestedBy || ""));
    setGuestCategoryInput(seat.category || 'other');
  };

  const saveSeat = () => {
    if (!selectedSeat) return;

    const updatedTables = tables.map(t => {
      if (t.id === selectedSeat.tableId) {
        return {
          ...t,
          seats: t.seats.map(s => {
            if (s.id === selectedSeat.seat.id) {
              return {
                ...s,
                guestName: guestNameInput,
                isReserved: !!guestNameInput,
                suggestedBy: null,
                category: guestCategoryInput
              };
            }
            return s;
          })
        };
      }
      return t;
    });
    onUpdateTables(updatedTables);
    setSelectedSeat(null);
  };

  const clearSeat = () => {
    setGuestNameInput("");
    if (!selectedSeat) return;
    const updatedTables = tables.map(t => {
      if (t.id === selectedSeat.tableId) {
        return {
          ...t,
          seats: t.seats.map(s => {
            if (s.id === selectedSeat.seat.id) {
              return { ...s, guestName: null, isReserved: false, suggestedBy: null, category: 'other' };
            }
            return s;
          })
        };
      }
      return t;
    });
    onUpdateTables(updatedTables);
    setSelectedSeat(null);
  };

  const approveSuggestion = () => {
    if (!selectedSeat?.seat.suggestedBy) return;
    setGuestNameInput(selectedSeat.seat.suggestedBy);
    // Logic will be handled by saveSeat which is called after modifying input? 
    // Actually need to update state immediately or set input and let user click save
    // Let's set input and auto-save
     const updatedTables = tables.map(t => {
      if (t.id === selectedSeat.tableId) {
        return {
          ...t,
          seats: t.seats.map(s => {
            if (s.id === selectedSeat.seat.id) {
              return {
                ...s,
                guestName: s.suggestedBy,
                isReserved: true,
                suggestedBy: null,
                category: guestCategoryInput
              };
            }
            return s;
          })
        };
      }
      return t;
    });
    onUpdateTables(updatedTables);
    setSelectedSeat(null);
  };

  // --- Table Rename Logic ---
  const startRenaming = (table: TableData) => {
    setEditingTableId(table.id);
    setTableNameInput(table.label);
  };

  const saveTableName = () => {
    if (editingTableId) {
      const updatedTables = tables.map(t => 
        t.id === editingTableId ? { ...t, label: tableNameInput } : t
      );
      onUpdateTables(updatedTables);
      setEditingTableId(null);
    }
  };

  // --- Helpers ---
  const getCategoryColor = (cat: GuestCategory) => {
    switch(cat) {
      case 'friend': return 'bg-green-500 border-green-600 text-white';
      case 'family_rafa': return 'bg-blue-500 border-blue-600 text-white';
      case 'family_laura': return 'bg-pink-500 border-pink-600 text-white';
      default: return 'bg-gray-200 border-gray-300 text-gray-500';
    }
  };

  return (
    <div className="flex flex-col h-full font-sans relative">
      {/* Toolbar */}
      <div className="bg-white p-3 border-b border-gray-200 shadow-sm flex flex-wrap items-center justify-between gap-4 z-20">
        <div className="flex items-center gap-2">
          <span className="text-sm font-bold text-gray-700 mr-2 flex items-center gap-2">
            <MousePointer2 className="w-4 h-4" /> Editor
          </span>
          <div className="h-6 w-px bg-gray-200 mx-2"></div>

          <button 
            onClick={() => handleAddTable('round')}
            className="flex items-center gap-2 px-3 py-1.5 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded text-sm transition-colors border border-gray-200"
          >
            <Circle className="w-3 h-3 text-blue-500" />
            + Redonda (10)
          </button>

          <button 
            onClick={() => handleAddTable('rect')}
            className="flex items-center gap-2 px-3 py-1.5 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded text-sm transition-colors border border-gray-200"
          >
            <Square className="w-3 h-3 text-green-500" />
            + Rectangular
          </button>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex gap-2 text-xs">
              <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-green-500"></span> Amigos</span>
              <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-blue-500"></span> Rafa</span>
              <span className="flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-pink-500"></span> Laura</span>
           </div>
           <button 
             onClick={handleSaveAll}
             className="flex items-center gap-2 px-4 py-2 bg-gray-900 text-white hover:bg-wedding-gold rounded text-sm font-bold transition-colors shadow-sm"
           >
             <Save className="w-4 h-4" />
             Guardar
           </button>
        </div>
      </div>

      <div className="flex-grow relative overflow-hidden flex">
        {/* Planner Area */}
        <div 
          className="flex-grow bg-slate-100 overflow-hidden cursor-crosshair relative"
          ref={containerRef}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
          style={{ backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)', backgroundSize: '30px 30px' }}
        >
          {tables.map((table) => {
             const occupiedCount = table.seats.filter(s => s.isReserved).length;
             const totalCount = table.seats.length;

             return (
              <div
                key={table.id}
                className={`absolute transform -translate-x-1/2 -translate-y-1/2 select-none group ${draggingTable === table.id ? 'z-50 cursor-grabbing' : 'z-10 cursor-grab'}`}
                style={{ left: `${table.x}%`, top: `${table.y}%` }}
                onMouseDown={(e) => handleMouseDown(e, table.id)}
              >
                {/* Direct Delete Button (Fixed) */}
                {editingTableId !== table.id && (
                  <button
                    onClick={(e) => {
                       // Stop propagation is critical here
                       e.stopPropagation(); 
                       e.preventDefault();
                       handleDeleteTable(table.id);
                    }}
                    onMouseDown={(e) => e.stopPropagation()} // Prevent drag start
                    className="delete-btn absolute -top-4 -right-4 w-6 h-6 bg-red-500 text-white rounded-full flex items-center justify-center shadow-md opacity-0 group-hover:opacity-100 transition-all hover:scale-110 hover:bg-red-600 z-[100] cursor-pointer"
                    title="Eliminar Mesa"
                  >
                    <X className="w-3 h-3" />
                  </button>
                )}

                {/* Table Body */}
                <div 
                  className={`
                    relative flex items-center justify-center shadow-xl border-4
                    transition-colors duration-200
                    ${draggingTable === table.id ? 'border-blue-400 bg-blue-50' : 'border-wedding-gold bg-white'}
                    ${table.type === 'rect' ? 'w-48 h-24 rounded-lg' : 'w-32 h-32 rounded-full'}
                  `}
                >
                  <div className="flex flex-col items-center justify-center">
                      {editingTableId === table.id ? (
                        <div className="absolute z-50 flex flex-col items-center gap-2 bg-white/90 p-2 rounded shadow-xl backdrop-blur-sm border border-gray-200">
                           <input 
                              autoFocus
                              className="w-32 text-center border border-gray-300 rounded px-1 py-0.5 text-sm focus:border-blue-500 focus:outline-none"
                              value={tableNameInput}
                              onChange={(e) => setTableNameInput(e.target.value)}
                              onKeyDown={(e) => e.key === 'Enter' && saveTableName()}
                           />
                           <button 
                                onClick={saveTableName}
                                className="w-full bg-green-500 text-white text-xs py-1 rounded hover:bg-green-600"
                           >
                               <Check className="w-3 h-3 mx-auto" />
                           </button>
                        </div>
                      ) : (
                        <div 
                          className="text-center cursor-text hover:bg-gray-100 px-2 py-1 rounded transition-colors"
                          onDoubleClick={() => startRenaming(table)}
                        >
                          <span className="font-bold text-sm text-gray-800 pointer-events-none block">{table.label}</span>
                          <span className="text-[10px] text-gray-500 font-mono mt-0.5">{occupiedCount}/{totalCount}</span>
                        </div>
                      )}
                  </div>

                  {/* Seats */}
                  {table.seats.map((seat, idx) => {
                     let style: React.CSSProperties = {};
                     let labelStyle: React.CSSProperties = {};

                     if (table.type === 'round') {
                       const angle = (idx * (360 / table.seats.length)) * (Math.PI / 180);
                       const radius = 65; 
                       // Position for the seat circle
                       style = { left: `calc(50% + ${Math.cos(angle) * radius}px)`, top: `calc(50% + ${Math.sin(angle) * radius}px)` };

                       // Position for the label (slightly further out)
                       const labelRadius = 90;
                       labelStyle = { 
                           left: `calc(50% + ${Math.cos(angle) * labelRadius}px)`, 
                           top: `calc(50% + ${Math.sin(angle) * labelRadius}px)`,
                           transform: 'translate(-50%, -50%)'
                       };

                     } else {
                       // Rectangular
                       style = { top: '50%', left: idx === 0 ? '-25px' : 'calc(100% + 25px)', transform: 'translate(-50%, -50%)' };
                       // Labels for rect
                       labelStyle = { 
                           top: '50%', 
                           left: idx === 0 ? '-80px' : 'calc(100% + 80px)',
                           transform: 'translate(-50%, -50%)',
                           width: '80px'
                       };
                     }

                     const hasSuggestion = !!seat.suggestedBy;
                     const isOccupied = seat.isReserved;
                     const colorClass = isOccupied ? getCategoryColor(seat.category) : (hasSuggestion ? 'bg-orange-100 border-orange-500 text-orange-700 animate-pulse' : 'bg-white border-gray-300 text-gray-400');

                     return (
                       <React.Fragment key={seat.id}>
                           {/* The Seat Circle */}
                           <div
                             className={`seat-node absolute w-9 h-9 rounded-full flex items-center justify-center cursor-pointer shadow-sm hover:scale-110 transition-transform border-2 z-20
                               ${table.type === 'round' ? '-translate-x-1/2 -translate-y-1/2' : ''}
                               ${colorClass}
                             `}
                             style={style}
                             onMouseDown={(e) => e.stopPropagation()} 
                             onClick={() => handleSeatClick(table.id, seat)}
                             onDragOver={handleDragOverSeat}
                             onDrop={(e) => handleDropOnSeat(e, table.id, seat)}
                           >
                             {hasSuggestion ? '?' : <User className="w-4 h-4" />}
                           </div>

                           {/* The Name Label */}
                           {(seat.guestName || seat.suggestedBy) && (
                               <div 
                                   className="absolute z-30 text-[10px] font-bold text-gray-700 bg-white/90 px-1.5 py-0.5 rounded shadow-sm border border-gray-200 whitespace-nowrap overflow-hidden max-w-[100px] text-ellipsis pointer-events-none"
                                   style={labelStyle}
                               >
                                   {seat.guestName || seat.suggestedBy}
                               </div>
                           )}
                       </React.Fragment>
                     );
                  })}
                </div>
              </div>
            );
          })}
        </div>

        {/* Guest List Sidebar (Draggable) */}
        <div className="w-64 bg-white border-l border-gray-200 flex flex-col shadow-xl z-30">
            <div className="p-3 bg-gray-50 border-b border-gray-200">
                <h3 className="font-cinzel font-bold text-gray-800 text-sm mb-2">Lista de Invitados</h3>
                <div className="relative">
                    <input 
                        type="text" 
                        placeholder="Buscar..."
                        className="w-full text-sm pl-8 pr-2 py-1.5 border rounded-md focus:outline-none focus:ring-1 focus:ring-wedding-gold"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                    <Search className="w-3 h-3 text-gray-400 absolute left-2.5 top-2.5" />
                </div>
            </div>

            <div className="flex-grow overflow-y-auto p-2 space-y-1 custom-scrollbar">
                {guests.length === 0 && (
                    <p className="text-xs text-gray-400 text-center py-4">No hay invitados en la lista.</p>
                )}
                {guests
                    .filter(g => g.fullName.toLowerCase().includes(searchTerm.toLowerCase()))
                    .sort((a, b) => a.fullName.localeCompare(b.fullName))
                    .map(guest => {
                        const seatedAt = seatedGuestsMap.get(guest.fullName.toLowerCase().trim());
                        return (
                            <div 
                                key={guest.id}
                                draggable
                                onDragStart={(e) => handleDragStartGuest(e, guest.fullName)}
                                className={`
                                    flex items-center justify-between p-2 rounded text-sm border cursor-grab active:cursor-grabbing hover:bg-gray-50
                                    ${seatedAt ? 'bg-green-50 border-green-100 opacity-60' : 'bg-white border-gray-200'}
                                `}
                            >
                                <div className="flex items-center gap-2 overflow-hidden">
                                    <GripVertical className="w-3 h-3 text-gray-300 flex-shrink-0" />
                                    <span className="truncate">{guest.fullName}</span>
                                </div>
                                {seatedAt && (
                                    <span className="text-[10px] bg-green-200 text-green-800 px-1 rounded ml-1 whitespace-nowrap">
                                        {seatedAt}
                                    </span>
                                )}
                            </div>
                        );
                    })
                }
            </div>
            <div className="p-2 bg-gray-50 border-t border-gray-200 text-[10px] text-gray-500 text-center">
                Arrastra un nombre a una silla para sentarlo.
            </div>
        </div>
      </div>

      {/* Seat Editor Modal */}
      {selectedSeat && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/40 backdrop-blur-sm">
          <div className="bg-white p-6 rounded-xl shadow-2xl w-full max-w-sm animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
                <User className="w-5 h-5 text-wedding-gold" />
                Editar Asiento
              </h3>
              <button onClick={() => setSelectedSeat(null)} className="text-gray-400 hover:text-gray-600">
                <X className="w-5 h-5" />
              </button>
            </div>

            {selectedSeat.seat.suggestedBy && !selectedSeat.seat.isReserved && (
              <div className="mb-4 bg-orange-50 border border-orange-200 p-3 rounded-lg">
                <p className="text-xs text-orange-600 font-bold uppercase mb-1">Sugerencia Recibida</p>
                <p className="text-gray-800">"{selectedSeat.seat.suggestedBy}" quiere este sitio.</p>
                <div className="flex gap-2 mt-2">
                  <button 
                    onClick={approveSuggestion}
                    className="flex-1 bg-green-500 text-white py-1 rounded text-sm hover:bg-green-600 flex items-center justify-center gap-1"
                  >
                    <Check className="w-3 h-3" /> Aprobar
                  </button>
                  <button 
                    onClick={clearSeat}
                    className="flex-1 bg-red-500 text-white py-1 rounded text-sm hover:bg-red-600 flex items-center justify-center gap-1"
                  >
                    <X className="w-3 h-3" /> Rechazar
                  </button>
                </div>
              </div>
            )}

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nombre del Invitado</label>
                <input 
                  type="text" 
                  value={guestNameInput}
                  onChange={(e) => setGuestNameInput(e.target.value)}
                  className="w-full border rounded p-2 focus:ring-2 focus:ring-wedding-gold outline-none"
                  placeholder="Vacío"
                  autoFocus
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Categoría (Color)</label>
                <div className="flex gap-2">
                   <button 
                     type="button"
                     onClick={() => setGuestCategoryInput('friend')}
                     className={`flex-1 py-2 text-xs rounded border transition-colors ${guestCategoryInput === 'friend' ? 'bg-green-500 text-white border-green-600' : 'bg-white hover:bg-green-50 text-gray-700'}`}
                   >
                     Amigos
                   </button>
                   <button 
                     type="button"
                     onClick={() => setGuestCategoryInput('family_rafa')}
                     className={`flex-1 py-2 text-xs rounded border transition-colors ${guestCategoryInput === 'family_rafa' ? 'bg-blue-500 text-white border-blue-600' : 'bg-white hover:bg-blue-50 text-gray-700'}`}
                   >
                     F. Rafa
                   </button>
                   <button 
                     type="button"
                     onClick={() => setGuestCategoryInput('family_laura')}
                     className={`flex-1 py-2 text-xs rounded border transition-colors ${guestCategoryInput === 'family_laura' ? 'bg-pink-500 text-white border-pink-600' : 'bg-white hover:bg-pink-50 text-gray-700'}`}
                   >
                     F. Laura
                   </button>
                </div>
              </div>

              <div className="flex justify-between pt-4 border-t border-gray-100">
                <button 
                  onClick={clearSeat}
                  className="text-red-500 hover:bg-red-50 px-3 py-2 rounded flex items-center gap-1 text-sm transition-colors"
                >
                  <Trash2 className="w-4 h-4" /> Liberar
                </button>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setSelectedSeat(null)}
                    className="px-4 py-2 text-gray-500 hover:text-gray-700 text-sm"
                  >
                    Cancelar
                  </button>
                  <button 
                    onClick={saveSeat}
                    className="bg-gray-900 text-white px-4 py-2 rounded hover:bg-gray-800 text-sm shadow-sm"
                  >
                    Guardar
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { Guest, TableData, Seat, GuestCategory } from "./types";

export const WEDDING_DATE = new Date('2026-10-10T17:00:00'); // 5 PM
export const VENUE_NAME = "El Poblet de las Atalayas";
export const VENUE_ADDRESS = "Alicante, España";

// Helper to assign random category for demo purposes
const getRandomCategory = (): GuestCategory => {
  const r = Math.random();
  if (r < 0.33) return 'friend';
  if (r < 0.66) return 'family_rafa';
  return 'family_laura';
};

// Helper to create seat data
const createSeats = (names: string[], tablePrefix: string): Seat[] => {
  // Pad with empty seats to make round tables look balanced (min 8 or 10)
  // For rectangular tables (like presidential), we just use the exact length usually, or min 2
  const isPresidential = tablePrefix === 'presi';
  const minSeats = isPresidential ? 2 : (names.length <= 8 ? 8 : 10);
  const totalSeats = Math.max(names.length, minSeats);

  return Array.from({ length: totalSeats }).map((_, i) => ({
    id: `${tablePrefix}-${i}`,
    guestName: names[i] || null,
    isReserved: !!names[i],
    suggestedBy: null,
    category: names[i] ? getRandomCategory() : 'other'
  }));
};

