            {selectedSeat.seat.suggestedBy && !selectedSeat.seat.isReserved && (
              <div className="mb-4 bg-orange-50 border border-orange-200 p-3 rounded-lg">
                <p className="text-xs text-orange-600 font-bold uppercase mb-1">Sugerencia Recibida</p>
