import React, { useState } from 'react';
import { User, X, AlertCircle } from 'lucide-react';
import { TableData, Seat } from '../types';

interface SeatingChartProps {
  tables: TableData[];
  onSuggestSeat: (tableId: string, seatId: string, name: string) => void;
}

export const SeatingChart: React.FC<SeatingChartProps> = ({ tables, onSuggestSeat }) => {
  const [selectedSeat, setSelectedSeat] = useState<{ tableId: string, seatId: string } | null>(null);
  const [requestName, setRequestName] = useState("");
  const [showModal, setShowModal] = useState(false);

  const handleSeatClick = (tableId: string, seat: Seat) => {
    // Guests can only click empty seats or seats they haven't already suggested/reserved
    if (!seat.isReserved && !seat.suggestedBy) {
      setSelectedSeat({ tableId, seatId: seat.id });
      setShowModal(true);
      setRequestName("");
    }
  };

  const handleRequestSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSeat || !requestName) return;

    onSuggestSeat(selectedSeat.tableId, selectedSeat.seatId, requestName);

    setShowModal(false);
    setSelectedSeat(null);
  };

  return (
    <div className="relative w-full h-[600px] lg:h-[800px] bg-stone-100 rounded-3xl shadow-2xl overflow-hidden [perspective:1000px] border-[6px] border-white group">

      {/* 3D Tilted Plane Container */}
      <div 
        className="absolute inset-0 w-full h-full transition-transform duration-1000 ease-out origin-center"
        style={{ transform: 'rotateX(20deg) scale(0.9) translateY(-20px)' }}
      >
        {/* Floor Pattern */}
        <div 
            className="absolute inset-0 bg-[#fbf9f4]" 
            style={{ 
                backgroundImage: 'radial-gradient(#d4af37 1.5px, transparent 1.5px)', 
                backgroundSize: '30px 30px',
                opacity: 0.4,
                boxShadow: 'inset 0 0 150px rgba(0,0,0,0.1)'
            }} 
        />

        {/* Tables */}
        {tables.map((table) => (
          <div
            key={table.id}
            className="absolute transform -translate-x-1/2 -translate-y-1/2 [transform-style:preserve-3d] transition-all duration-500 hover:z-50"
            style={{ left: `${table.x}%`, top: `${table.y}%` }}
          >
            {/* Table Body (The physical object) */}
            <div 
              className={`
                relative flex items-center justify-center 
                bg-white
                border-[6px] border-double border-wedding-gold/30
                shadow-[0_20px_30px_-5px_rgba(0,0,0,0.2)]
                transition-transform duration-300 group-hover:translate-z-10
                ${table.type === 'rect' ? 'w-56 h-28 rounded-xl' : 'w-28 h-28 md:w-40 md:h-40 rounded-full'}
              `}
            >
              {/* Table Cloth Texture Overlay */}
              <div className="absolute inset-0 bg-white opacity-80 rounded-[inherit]" />

              {/* Centerpiece / Label */}
              <div className="relative z-10 bg-white/90 backdrop-blur-sm px-4 py-2 rounded-full shadow-sm border border-wedding-gold/20 transform transition-transform duration-300 hover:scale-110">
                <span className="font-cinzel text-gray-800 font-bold text-xs md:text-sm tracking-wide whitespace-nowrap">
                  {table.label}
                </span>
              </div>

              {/* Seats */}
              {table.seats.map((seat, idx) => {
                // Calculation logic
                let style: React.CSSProperties = {};

                if (table.type === 'round') {
                  const angle = (idx * (360 / table.seats.length)) * (Math.PI / 180);
                  const radius = 85; // Distance from center in px (visually tuned for 3D)

                  style = {
                    left: `calc(50% + ${Math.cos(angle) * radius}px)`,
                    top: `calc(50% + ${Math.sin(angle) * radius}px)`,
                  };
                } else {
                  // Rectangular
                  style = {
                    top: '50%',
                    left: idx === 0 ? '-35px' : 'calc(100% + 35px)',
                    transform: 'translate(-50%, -50%)' 
                  };
                }

                const isPending = !!seat.suggestedBy;
                const isReserved = seat.isReserved;

                return (
                  <div
                    key={seat.id}
                    onClick={() => handleSeatClick(table.id, seat)}
                    className={`
                      absolute w-10 h-10 md:w-12 md:h-12 rounded-full flex items-center justify-center cursor-pointer group/seat
                      transition-all duration-300 shadow-md z-20
                      ${table.type === 'round' ? '-translate-x-1/2 -translate-y-1/2' : ''}
                      ${isReserved 
                        ? 'bg-gradient-to-br from-pink-50 to-pink-100 border-2 border-white ring-1 ring-pink-200' 
                        : isPending 
                          ? 'bg-gradient-to-br from-orange-50 to-orange-100 border-2 border-white ring-1 ring-orange-200' 
                          : 'bg-white border-2 border-white ring-1 ring-gray-200 hover:-translate-y-1 hover:shadow-lg hover:ring-wedding-gold hover:bg-yellow-50'}
                    `}
                    style={style}
                  >
                    {/* Seat Content */}
                    {isReserved ? (
                      <span className="font-cinzel font-bold text-pink-900/70 text-sm">
                         {seat.guestName ? seat.guestName.charAt(0).toUpperCase() : <User className="w-4 h-4"/>}
                      </span>
                    ) : isPending ? (
                      <AlertCircle className="w-4 h-4 text-orange-400" />
                    ) : (
                       <div className="w-2 h-2 rounded-full bg-wedding-gold/20 group-hover/seat:bg-wedding-gold transition-colors" />
                    )}

                    {/* Hover Tooltip (3D Floating) */}
                    <div className="absolute bottom-full mb-3 opacity-0 group-hover/seat:opacity-100 transition-all duration-300 pointer-events-none transform translate-y-2 group-hover/seat:translate-y-0 z-50">
                      <div className="bg-gray-800 text-white text-xs py-1.5 px-3 rounded-lg shadow-xl whitespace-nowrap relative">
                         {isReserved ? seat.guestName : isPending ? "Solicitud pendiente" : "¡Siéntate aquí!"}
                         <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-800"></div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>

      {/* Legend Overlay (Flat) */}
      <div className="absolute top-6 left-6 z-40 bg-white/90 backdrop-blur-md p-5 rounded-2xl shadow-xl border border-white/50 max-w-[200px] animate-in slide-in-from-left duration-700">
        <h4 className="font-cinzel text-gray-900 font-bold text-xs mb-4 uppercase tracking-widest border-b border-gray-100 pb-2">Leyenda</h4>
        <div className="space-y-3 text-xs font-sans text-gray-600">
           <div className="flex items-center gap-3">
              <div className="w-5 h-5 rounded-full bg-gradient-to-br from-pink-50 to-pink-100 border border-white ring-1 ring-pink-200 shadow-sm flex items-center justify-center text-[10px] font-bold text-pink-800">R</div>
              <span>Ocupado</span>
           </div>
           <div className="flex items-center gap-3">
              <div className="w-5 h-5 rounded-full bg-gradient-to-br from-orange-50 to-orange-100 border border-white ring-1 ring-orange-200 shadow-sm flex items-center justify-center">
                 <AlertCircle className="w-3 h-3 text-orange-400" />
              </div>
              <span>Solicitado</span>
           </div>
           <div className="flex items-center gap-3">
              <div className="w-5 h-5 rounded-full bg-white border border-white ring-1 ring-gray-200 shadow-sm flex items-center justify-center">
                 <div className="w-1.5 h-1.5 rounded-full bg-wedding-gold/30"></div>
              </div>
              <span>Disponible</span>
           </div>
        </div>
      </div>

      {/* Request Seat Modal */}
      {showModal && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-sm p-4">
          <div className="bg-white p-6 rounded-2xl shadow-2xl max-w-sm w-full animate-in zoom-in duration-300 border border-white/50">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-cinzel text-lg font-bold text-gray-800">Sugerir Sitio</h3>
              <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-gray-600 transition-colors">
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="bg-amber-50 p-3 rounded-lg border border-amber-100 mb-4">
               <p className="text-xs text-amber-800 leading-relaxed">
                  ¿Te gustaría sentarte aquí? Envíanos tu nombre.
                  <span className="block font-bold mt-1 opacity-80">* Los novios deberán confirmarlo.</span>
               </p>
            </div>

            <form onSubmit={handleRequestSubmit}>
              <div className="relative mb-4">
                 <User className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                 <input 
                    type="text" 
                    placeholder="Tu Nombre Completo" 
                    autoFocus
                    required
                    className="w-full border border-gray-200 bg-gray-50 rounded-lg py-2 pl-9 pr-3 text-sm focus:border-wedding-gold focus:ring-1 focus:ring-wedding-gold focus:outline-none transition-all"
                    value={requestName}
                    onChange={(e) => setRequestName(e.target.value)}
                 />
              </div>
              <button 
                type="submit" 
                className="w-full bg-gray-900 text-white py-2.5 rounded-lg hover:bg-wedding-gold hover:shadow-lg transition-all duration-300 font-cinzel text-sm tracking-wide"
              >
                Enviar Sugerencia
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

