import { Users, Utensils, XCircle, CheckCircle, Bus, LayoutGrid, List, Filter } from 'lucide-react';
import { SeatingPlanner } from './SeatingPlanner';

interface AdminDashboardProps {
  guests: Guest[];
  tables: TableData[];
  onUpdateTables: (tables: TableData[]) => void;
  onLogout: () => void;
}

