          >
            <List className="w-4 h-4" /> Estadísticas
          </button>
          <button 
            onClick={() => setActiveTab('seating')}
            className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'seating' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500 hover:text-gray-700'}`}
